SELECT DISTINCT pm.category
FROM TS.sales s
INNER JOIN TS.product_master pm ON s.product_id = pm.product_id;

SELECT COUNT(product_id) AS products_by_category
FROM TS.product_master
WHERE category = 'Electronics';

SELECT COUNT(store_id) AS number_of_stores
FROM TS.location_master
WHERE state = 'California';

SELECT DISTINCT lm.store_name
FROM TS.location_master lm
INNER JOIN TS.sales s ON lm.store_id = s.store_id;

SELECT COUNT(DISTINCT transaction_id) AS distinct_transactions
FROM TS.sales
WHERE YEAR(sale_date) = 2025;

SELECT SUM(total_revenue) AS total_sales_revenue
FROM TS.sales
WHERE sale_date >= '2025-01-01' AND sale_date < '2025-02-01';
